764	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
765	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
766	// DDx-authored beads always round-trip through `bd import`. Empirically
767	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
768	const MaxFieldBytes = 65535
769	
770	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
771	// need to preserve the full payload should persist it to a sidecar artifact
772	// and store a path reference in the field; this function is the defense-in-
773	// depth cap for code paths that don't. Returns the input unchanged when it
774	// fits; otherwise returns head+tail truncation with a byte-count marker.
775	func capFieldBytes(s string) string {
776		if len(s) <= MaxFieldBytes {
777			return s
778		}
779		// Reserve a marker that always fits; keep head heavy (2/3) so
780		// human-readable context is preserved for the common short-rationale case.
781		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
782		budget := MaxFieldBytes - len(marker)
783		if budget <= 0 {
784			return s[:MaxFieldBytes]
785		}
786		head := (budget * 2) / 3
787		tail := budget - head
788		return s[:head] + marker + s[len(s)-tail:]
789	}

