632	// projectScoped is middleware for /api/projects/{project}/... routes.
633	// It pulls {project} out of the path, resolves it to a registered ProjectEntry,
634	// and injects the entry into the request context. Requests whose project does
635	// not resolve get 404.
636	func (s *Server) projectScoped(next http.HandlerFunc) http.HandlerFunc {
637		return func(w http.ResponseWriter, r *http.Request) {
638			key := r.PathValue("project")
639			entry, ok := s.resolveProject(key)
640			if !ok {
641				writeJSON(w, http.StatusNotFound, map[string]string{"error": "project not found"})
642				return
643			}
644			next(w, r.WithContext(withProjectContext(r.Context(), entry)))
645		}
646	}
