648	// singletonScoped is middleware for legacy /api/... routes. When exactly one
649	// project is registered, it injects that project into the request context so
650	// legacy handlers behave identically to the scoped /api/projects/{id}/...
651	// equivalent. When zero or more than one project is registered the request
652	// passes through unchanged, preserving the historical multi-project aggregate
653	// behavior of list endpoints and the server's own WorkingDir default for
654	// single-item endpoints.
655	func (s *Server) singletonScoped(next http.HandlerFunc) http.HandlerFunc {
656		return func(w http.ResponseWriter, r *http.Request) {
657			projects := s.state.GetProjects()
658			if len(projects) == 1 {
659				r = r.WithContext(withProjectContext(r.Context(), projects[0]))
660			}
661			next(w, r)
662		}
663	}
