141	// runVirtualFn replays a recorded response from the dictionary or inline responses.
142	func runVirtualFn(r *Runner, opts RunArgs) (*Result, error) {
143		prompt, err := r.resolvePrompt(opts)
144		if err != nil {
145			return nil, err
146		}
147	
148		// Check DDX_VIRTUAL_RESPONSES env var first (inline pattern-based matching).
149		if envResponses := os.Getenv("DDX_VIRTUAL_RESPONSES"); envResponses != "" {
150			var responses []InlineResponse
151			if err := json.Unmarshal([]byte(envResponses), &responses); err != nil {
152				return nil, fmt.Errorf("parsing DDX_VIRTUAL_RESPONSES: %w", err)
153			}
154			if ir, ok := LookupInline(responses, prompt); ok {
155				return buildVirtualResultFn(r, ir.Response, ir.ExitCode, ir.Model, ir.DelayMS, 0, 0, 0, prompt, opts), nil
156			}
157		}
158	
159		// Fall back to file-based dictionary lookup.
160		dictDir := filepath.Join(r.Config.SessionLogDir, "..", "agent-dictionary")
161		if _, err := os.Stat(VirtualDictionaryDir); err == nil {
162			dictDir = VirtualDictionaryDir
163		}
164	
165		var patterns []config.NormalizePattern
166		if cfg, err := config.Load(); err == nil && cfg.Agent != nil && cfg.Agent.Virtual != nil {
167			patterns = cfg.Agent.Virtual.Normalize
168		}
169	
170		entry, err := LookupEntry(dictDir, prompt, patterns...)
171		if err != nil {
172			return nil, err
173		}
174	
175		return buildVirtualResultFn(r, entry.Response, entry.ExitCode, entry.Model, entry.DelayMS,
176			entry.InputTokens, entry.OutputTokens, entry.CostUSD, prompt, opts), nil
177	}
178	
179	func buildVirtualResultFn(r *Runner, response string, exitCode int, model string, delayMS int,
180		inputTokens, outputTokens int, costUSD float64, prompt string, opts RunArgs) *Result {
181	
182		if delayMS > 0 {
183			time.Sleep(time.Duration(delayMS) * time.Millisecond)
184		}
185	
186		result := &Result{
187			Harness:      "virtual",
188			Model:        model,
189			Output:       response,
190			ExitCode:     exitCode,
191			DurationMS:   delayMS,
192			InputTokens:  inputTokens,
193			OutputTokens: outputTokens,
194			Tokens:       inputTokens + outputTokens,
195			CostUSD:      costUSD,
196		}
197	
198		promptSource := opts.PromptSource
199		if promptSource == "" {
200			if opts.PromptFile != "" {
201				promptSource = opts.PromptFile
202			} else {
203				promptSource = "inline"
204			}
205		}
206		r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
207		return result
208	}
